  // ── SELF-ADVOCACY STRENGTHS ASSESSMENT ──
  // 60 items across 6 strands. Each item: 0-3 rating. Aggregate
  // gives a 6-dimension radar profile.
  // ══════════════════════════════════════════════════════════════
  var SELF_ADVOCACY_STRANDS = [
    { id: 'knowSelf', name: 'Know Yourself', icon: '🪞', color: '#a855f7',
      desc: 'You can accurately name what helps you, what hurts you, what you\'re good at, and what you\'re working on. Self-knowledge is the foundation of self-advocacy.' },
    { id: 'knowRights', name: 'Know Your Rights', icon: '⚖️', color: '#0ea5e9',
      desc: 'You understand the legal, school, and social rights you have. You can cite specific policies and laws when needed.' },
    { id: 'communicate', name: 'Communicate Clearly', icon: '💬', color: '#22c55e',
      desc: 'You can name what you need, what you observed, and what you want — clearly and specifically. Not vaguely, not aggressively, not apologetically.' },
    { id: 'persist', name: 'Persist Through Friction', icon: '🪨', color: '#f59e0b',
      desc: 'When you don\'t get what you asked for the first time, you can ask again. You don\'t personalize "no." You know when to push and when to wait.' },
    { id: 'collaborate', name: 'Build Allies', icon: '🤝', color: '#ec4899',
      desc: 'You don\'t advocate alone. You know who has your back, who has institutional power, and who to bring in for what.' },
    { id: 'regulate', name: 'Regulate Under Stress', icon: '🌊', color: '#06b6d4',
      desc: 'When advocating gets hard — emotionally, socially, or in the moment — you have ways to stay regulated enough to keep going. You know your edges.' }
  ];
