    { strand: 'regulate', q: 'I know what helps me calm down in 60 seconds.' },
    { strand: 'regulate', q: 'I can take a break when I need one.' },
    { strand: 'regulate', q: 'I can tell when I\'m too dysregulated to have a hard conversation right now.' },
    { strand: 'regulate', q: 'I can come back to a conversation later if I needed to step away.' },
    { strand: 'regulate', q: 'I can recover from a conversation that didn\'t go well.' },
    { strand: 'regulate', q: 'I don\'t shut down completely when an adult raises their voice.' },
    { strand: 'regulate', q: 'I can name a feeling in the moment without acting on it impulsively.' },
    { strand: 'regulate', q: 'I have strategies that work for me when I\'m overwhelmed.' },
    { strand: 'regulate', q: 'I can ask to pause a meeting if I need to.' },
    { strand: 'regulate', q: 'I can tell the difference between "this is hard" and "this is unsafe."' }
