  // ══════════════════════════════════════════════════════════════
  // ── IDENTITY AFFIRMATION CARDS — strengths, identity, voice ──
  // ══════════════════════════════════════════════════════════════
  var IDENTITY_CARDS = [
    { id: 'i1', text: 'Asking for what I need is the work, not the failure of work.' },
    { id: 'i2', text: 'My accommodations are not a head start. They\'re a level playing field.' },
    { id: 'i3', text: 'I do not owe anyone an explanation of my disability.' },
    { id: 'i4', text: 'My discomfort with asking is not a sign I shouldn\'t ask.' },
    { id: 'i5', text: 'The right tools change what I can do, not who I am.' },
    { id: 'i6', text: 'My way of thinking is not less. It is different.' },
    { id: 'i7', text: 'Self-advocacy is a skill I am building. Not a personality trait I lack.' },
    { id: 'i8', text: 'I have the right to ask. Their reaction is not my responsibility.' },
    { id: 'i9', text: 'I get to choose who knows what about me. Disclosure is a tool, not an obligation.' },
    { id: 'i10', text: 'I am allowed to need things and also be smart, capable, and kind.' },
    { id: 'i11', text: 'Resting is not laziness. It\'s how I become available for what matters.' },
    { id: 'i12', text: 'I can change my mind without that being weak.' },
    { id: 'i13', text: 'When someone says no, I am still allowed to ask again.' },
    { id: 'i14', text: 'I do not need to apologize for taking up space.' },
    { id: 'i15', text: 'My voice belongs in the rooms where decisions about me get made.' },
    { id: 'i16', text: 'Being neurodivergent is part of me. It is not something to apologize for.' },
    { id: 'i17', text: 'I am allowed to need different things on different days.' },
    { id: 'i18', text: 'Boundaries are not walls. They are doors with locks I control.' },
    { id: 'i19', text: 'Being heard is not the same as being agreed with.' },
    { id: 'i20', text: 'I can be soft and firm at the same time.' },
    { id: 'i21', text: 'Documentation is not adversarial. It is protective.' },
    { id: 'i22', text: 'Asking for help with one thing does not mean I cannot do anything.' },
    { id: 'i23', text: 'I get to set the pace of my disclosure.' },
    { id: 'i24', text: 'My past self did the best they could with what they knew.' },
    { id: 'i25', text: 'Growth is uneven. I do not have to be perfect at this to be improving.' },
    { id: 'i26', text: 'Other people\'s discomfort with my needs is not a sign my needs are wrong.' },
    { id: 'i27', text: 'I can advocate for myself AND care about other people. They are not opposites.' },
    { id: 'i28', text: 'I am building a life where I do not have to mask all day.' },
    { id: 'i29', text: 'My future is not predicted by the parts of school that are hardest right now.' },
    { id: 'i30', text: 'There are adults who will get it. I do not have to keep explaining to the ones who won\'t.' },
    { id: 'i31', text: 'Self-advocacy is a marathon. I can pace myself.' },
    { id: 'i32', text: 'My quietness is not the same as my consent.' },
    { id: 'i33', text: 'The version of me that masks is not more real than the version of me that doesn\'t.' },
    { id: 'i34', text: 'I am allowed to ask follow-up questions.' },
    { id: 'i35', text: 'My disability is not a deficit of character.' },
    { id: 'i36', text: 'I get to be a beginner at hard things.' },
    { id: 'i37', text: 'Walking away is sometimes the strongest move I can make.' },
    { id: 'i38', text: 'I do not have to perform okay-ness for other people\'s comfort.' },
    { id: 'i39', text: 'My body is information. It is not betraying me when it\'s tired.' },
    { id: 'i40', text: 'I can be sure about a need without being sure about everything.' },
    { id: 'i41', text: 'There is no "advocacy quota." Each day starts fresh.' },
    { id: 'i42', text: 'My capacity is real, and naming its edges is wisdom, not weakness.' },
    { id: 'i43', text: 'My ancestors fought for these protections. Using them honors them.' },
    { id: 'i44', text: 'I am not the first person to need this. I will not be the last.' },
    { id: 'i45', text: 'My questions matter. My doubts matter. My voice matters.' },
    { id: 'i46', text: 'I get to disappoint people sometimes. That is the cost of having boundaries.' },
    { id: 'i47', text: 'The world will not collapse if I ask for what I need.' },
    { id: 'i48', text: 'Crying does not invalidate what I am saying.' },
    { id: 'i49', text: 'My silence is sometimes loud. I do not always have to fill it.' },
    { id: 'i50', text: 'I can have a hard day and still be doing this right.' },
    { id: 'i51', text: 'The right person at the right time can change everything.' },
    { id: 'i52', text: 'I am building a track record. Each ask makes the next easier.' },
    { id: 'i53', text: 'I am not "too sensitive." I am a person responding to my environment.' },
    { id: 'i54', text: 'Being seen accurately is sometimes the entire point.' },
    { id: 'i55', text: 'My pace is my pace. Other people\'s timelines do not have to be mine.' },
    { id: 'i56', text: 'I am allowed to share something AND want it kept private.' },
    { id: 'i57', text: 'I can love someone AND disagree with them.' },
    { id: 'i58', text: 'My past does not get a vote on what I ask for now.' },
    { id: 'i59', text: 'I have the right to take notes during meetings about me.' },
    { id: 'i60', text: 'The phrase "I changed my mind" is a complete sentence.' },
    { id: 'i61', text: 'Some adults need a year to understand. Some need ten minutes. I can choose where I spend my time.' },
    { id: 'i62', text: 'I do not have to justify a "no" to be allowed to say it.' },
    { id: 'i63', text: 'The discomfort of asking is shorter than the cost of not asking.' },
    { id: 'i64', text: 'My need does not have to look like everyone else\'s need to be valid.' },
    { id: 'i65', text: 'I have the right to say "I don\'t know yet."' },
    { id: 'i66', text: 'My identity is not a hypothesis to be tested.' },
    { id: 'i67', text: 'I get to revise my own story.' },
    { id: 'i68', text: 'When someone tells me who I am, I can listen and decide if they\'re right.' },
    { id: 'i69', text: 'The work I do today, no one may see for years. It still counts.' },
    { id: 'i70', text: 'I am not less because something is hard for me that\'s easy for others.' },
    { id: 'i71', text: 'I can decide to leave a conversation. I do not need permission.' },
    { id: 'i72', text: 'When my needs are dismissed, my needs are still real.' },
    { id: 'i73', text: 'Being known is more important than being liked.' },
    { id: 'i74', text: 'Hard conversations get a little easier each time.' },
    { id: 'i75', text: 'My life is not a problem to be solved.' },
    { id: 'i76', text: 'I can wait until I am ready.' },
    { id: 'i77', text: 'I am not a burden. I am a person in relation with other people.' },
    { id: 'i78', text: 'My future is bigger than any one bad day.' },
    { id: 'i79', text: 'The way I have always been treated is not the way I have to keep being treated.' },
    { id: 'i80', text: 'My voice gets steadier with practice. So does yours.' },
    { id: 'i81', text: 'I have permission to stop performing.' },
    { id: 'i82', text: 'It is okay for my needs to change as I change.' },
    { id: 'i83', text: 'Disagreement does not equal disrespect.' },
    { id: 'i84', text: 'I get to ask "what do you mean?" as many times as I need to.' },
    { id: 'i85', text: 'I am allowed to be confident AND wrong.' },
    { id: 'i86', text: 'I can be angry without being mean.' },
    { id: 'i87', text: 'The way I cope is not always the way other people would cope. Both can be valid.' },
    { id: 'i88', text: 'My voice belongs in this conversation.' },
    { id: 'i89', text: 'I do not have to soften my truth to make it acceptable.' },
    { id: 'i90', text: 'My experience is data.' },
    { id: 'i91', text: 'I can have a "no" and "I love you" in the same sentence.' },
    { id: 'i92', text: 'There is no advocacy without rest. Both are part of the work.' },
    { id: 'i93', text: 'My consent matters even when no one is asking for it.' },
    { id: 'i94', text: 'I do not have to be brave today.' },
    { id: 'i95', text: 'My limits are useful information about what I need to thrive.' },
    { id: 'i96', text: 'I can be a learner. I do not have to perform expertise.' },
    { id: 'i97', text: 'The shape of help I need is mine to define.' },
    { id: 'i98', text: 'It is not arrogance to know what I need.' },
    { id: 'i99', text: 'My way of being is part of what the world needs.' },
    { id: 'i100', text: 'I am allowed to grow at my own pace.' }
  ];

